# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.bidi_extraction.obligate","kind":"function","src_hash":"2c97e2891f07b3ce","in":{"base":"str","pred":"isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef))"},"out":{"base":"ObligationBundle"},"spec":{"lhs":"obligate(sou)","rhs":"generate proof obligations from python source code","over":{"base":"str","pred":"isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef))"},"name":"obligate_correct"},"guarantee":"generate proof obligations from python source code","fibers":[{"name":"(ast_FunctionDef","pred":"isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef))","path":{"lhs":"obligate(x)","rhs":"generate proof obligations from python source code","over":{"base":"(ast.FunctionDef","pred":"isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef))"},"name":"obligate_(ast.FunctionDef_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.bidi_extraction.obligate_(ast.FunctionDef_correct","statement":"obligate satisfies spec on (ast.FunctionDef inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":1,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"b13af4e1a82ffe49"}
def obligate(source: str, guarantee_text: str = '',
             libraries: Optional[List[str]] = None) -> ObligationBundle:
    """Generate proof obligations from Python source code.

    This is the BACKWARD direction of bidirectional extraction:
    given code and a spec, what needs to be proved?

    Pythonic obligations generated:
    - None-safety for every Optional return
    - Exception coverage for try/except
    - Per-fiber type obligations from duck typing
    - Library contract obligations for external calls
    - Dict shape obligations for dict returns
    - Mutation safety for in-place operations
    - Termination for recursive functions
    """
    try:
        tree = ast.parse(textwrap.dedent(source))
    except SyntaxError:
        bundle = ObligationBundle("unknown", source)
        bundle.add(ProofObligation(
            kind=ObligationKind.POSTCONDITION,
            description="could not parse source",
            severity='required',
        ))
        return bundle

    # Find the function definition
    func_def = None
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            func_def = node
            break

    func_name = func_def.name if func_def else 'unknown'
    bundle = ObligationBundle(func_name, source)
    bundle.library_deps = libraries or []

    if guarantee_text:
        bundle.add(ProofObligation(
            kind=ObligationKind.POSTCONDITION,
            description=guarantee_text,
            suggested_tactic='auto',
        ))

    if func_def is None:
        return bundle

    # Analyze the function body
    _analyze_none_safety(func_def, bundle)
    _analyze_exception_safety(func_def, bundle)
    _analyze_duck_type_fibers(func_def, bundle)
    _analyze_library_calls(func_def, bundle, libraries or [])
    _analyze_dict_shapes(func_def, bundle)
    _analyze_mutation(func_def, bundle)
    _analyze_recursion(func_def, bundle)
    _analyze_loop_invariants(func_def, bundle)

    return bundle


