# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.bidi_extraction.verify_against_obligations","kind":"function","src_hash":"c3321743579f8135","in":{"base":"str"},"out":{"base":"Tuple[VerifiedExtraction, ObligationBundle]"},"spec":{"lhs":"verify_against_obligations(sou)","rhs":"full round-trip: generate obligations, check proof covers them","over":{"base":"str"},"name":"verify_against_obligations_correct"},"guarantee":"full round-trip: generate obligations, check proof covers them","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.bidi_extraction.verify_against_obligations_correct","statement":"Path(verify_against_obligations(x), full round-trip: generate obligations, check proof covers them)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"9c6762929b879565"}
def verify_against_obligations(
    source: str,
    guarantee: str,
    proof: ProofTerm,
    libraries: Optional[List[str]] = None,
) -> Tuple[VerifiedExtraction, ObligationBundle]:
    """Full round-trip: generate obligations, check proof covers them.

    Returns the extraction result AND the obligation bundle showing
    which obligations were resolved by the proof.
    """
    # Backward: generate obligations
    bundle = obligate(source, guarantee, libraries)

    # Compile to OTerms
    result = compile_to_oterm(source)
    if result is None:
        return (VerifiedExtraction(
            source=source,
            function_name=bundle.function_name,
            guarantee=guarantee,
        ), bundle)

    oterm, _warnings = result

    # Forward: extract with proof
    extraction = extract_verified(
        function_name=bundle.function_name,
        proof=proof,
        lhs=oterm,
        rhs=oterm,
        guarantee=guarantee,
    )

    # Match proof provenances to obligations
    _resolve_obligations(bundle, extraction)

    extraction.resolved_obligations = [o for o in bundle.obligations if o.resolved]
    return extraction, bundle


